python3 -c "
import json, sys

events_path = '.yoyo/state/events.jsonl'

error_completed = {}
failure_observed_runs = set()

with open(events_path, encoding='utf-8', errors='replace') as f:
    for line in f:
        line = line.strip()
        if not line:
            continue
        try:
            event = json.loads(line)
        except json.JSONDecodeError:
            continue

        kind = event.get('event_type') or event.get('kind') or ''
        payload = event.get('payload', {})
        if isinstance(payload, dict):
            wrapped = payload.get('value')
            if set(payload.keys()).issubset({'_yoyo', 'value'}) and isinstance(wrapped, dict):
                payload = wrapped

        rid = event.get('run_id') or payload.get('run_id') or payload.get('_yoyo', {}).get('run_id') or ''

        if not rid:
            continue

        if kind == 'RunCompleted':
            status = payload.get('status', '')
            if status and status not in ('success', 'completed'):
                error_completed[rid] = {'status': status, 'timestamp_ms': event.get('timestamp_ms', 0)}
        elif kind == 'FailureObserved':
            failure_observed_runs.add(rid)

missing = {rid: info for rid, info in error_completed.items() if rid not in failure_observed_runs}

print(f'Error-completed runs: {len(error_completed)}')
print(f'FailureObserved runs: {len(failure_observed_runs)}')
print(f'Missing FailureObserved: {len(missing)}')
for rid, info in sorted(missing.items()):
    print(f'  run_id={rid} status={info[\"status\"]}')
" 2>&1

